const fs = require('fs');
const path = require('path');

const data = $input.first().json;
const workflows = data.data || [];
const date = new Date().toISOString().split('T')[0];
const backupDir = `/home/clawdbot/dev-sandbox/projects/shared/n8n-workflows/backups/${date}`;

// Create backup directory
fs.mkdirSync(backupDir, { recursive: true });

const results = [];
let exported = 0;
let failed = 0;

for (const wf of workflows) {
  if (wf.isArchived) continue;

  try {
    // Fetch full workflow
    const fullWf = await this.helpers.httpRequest({
      method: 'GET',
      url: `http://localhost:5678/api/v1/workflows/${wf.id}`,
      headers: { 'Accept': 'application/json' }
    });

    // Clean name for filename
    const safeName = wf.name.replace(/[^a-zA-Z0-9-_]/g, '-');
    const filePath = path.join(backupDir, `${safeName}.json`);

    fs.writeFileSync(filePath, JSON.stringify(fullWf, null, 2));
    exported++;
    results.push(`OK: ${wf.name}`);
  } catch (err) {
    failed++;
    results.push(`FAIL: ${wf.name} - ${err.message}`);
  }
}

// Git commit the backup
try {
  const { execSync } = require('child_process');
  const gitDir = '/home/clawdbot/dev-sandbox';
  execSync(`cd ${gitDir} && git add projects/shared/n8n-workflows/backups/ && git commit -m "n8n backup ${date} (${exported} workflows)" && git push`, {
    timeout: 60000,
    encoding: 'utf8'
  });
  results.push(`\nGit: committed and pushed ${exported} workflow backups`);
} catch (gitErr) {
  results.push(`\nGit: ${gitErr.message}`);
}

const summary = `📦 N8N MONTHLY BACKUP\n\nDate: ${date}\nExported: ${exported}/${workflows.filter(w => !w.isArchived).length}\nFailed: ${failed}\nLocation: ${backupDir}\n\n${results.join('\n')}`;

return [{ json: { summary, exported, failed, date, backupDir } }];

