// Parse GitHub webhook push payload
const body = $input.first().json.body || $input.first().json;

// Extract key fields
const repo = body.repository?.full_name || 'unknown';
const branch = (body.ref || '').replace('refs/heads/', '');
const pusher = body.pusher?.name || body.sender?.login || 'unknown';
const commits = body.commits || [];
const compareUrl = body.compare || '';

// Determine which agent pushed
let agent = 'Unknown';
if (pusher === 'clawdbot' || pusher.includes('clawdbot')) agent = 'Clawdbot (EC2)';
else if (pusher === 'ralph' || pusher.includes('ralph')) agent = 'Ralph (EC2)';
else if (pusher === 'wmarceau' || pusher === 'williammarceaujr.' || pusher.includes('marceau')) agent = 'Claude Code (Mac)';
else agent = pusher;

// Check if HANDOFF.md was modified
const handoffModified = commits.some(c => 
  (c.added || []).concat(c.modified || []).includes('HANDOFF.md')
);

// Build commit summary (max 5)
const commitLines = commits.slice(0, 5).map((c, i) => {
  const msg = c.message.split('\n')[0].substring(0, 80);
  return `  ${i + 1}. ${msg}`;
}).join('\n');

const extraCommits = commits.length > 5 ? `\n  ... and ${commits.length - 5} more` : '';

// Format Telegram message (HTML)
let message = `<b>\ud83d\udce6 Push to ${repo}</b>\n`;
message += `<b>Branch:</b> ${branch}\n`;
message += `<b>Agent:</b> ${agent}\n`;
message += `<b>Commits:</b> ${commits.length}\n\n`;
message += `${commitLines}${extraCommits}\n`;

if (handoffModified) {
  message += `\n<b>\ud83d\udce8 HANDOFF.md was updated!</b>\nCheck for new tasks: <code>cat HANDOFF.md</code>`;
}

if (compareUrl) {
  message += `\n\n<a href="${compareUrl}">View changes on GitHub</a>`;
}

return [{
  json: {
    message,
    chatId: '5692454753',
    handoffModified,
    agent,
    branch,
    repo,
    commitCount: commits.length
  }
}];

