parameters.jsCode:
const items = $input.all();
const results = [];

for (const item of items) {
 const data = item.json;
 const phone = data.phone || 'Unknown';
 const message = data.message || '';
 const numMedia = parseInt(data.numMedia || '0', 10);
 const messageSid = data.messageSid || '';

 let notification = '';

 if (numMedia > 0) {
 const media = [];
 for (let i = 0; i < Math.min(numMedia, 5); i++) {
 const url = data['mediaUrl' + i] || '';
 const type = data['mediaType' + i] || '';
 if (url) media.push({ url, type });
 }

 const hasPhoto = media.some(m => m.type.startsWith('image/'));
 const hasVoice = media.some(m => m.type.startsWith('audio/'));
 const hasVideo = media.some(m => m.type.startsWith('video/'));

 let icon = '📎';
 let label = 'MEDIA';
 if (hasPhoto && hasVoice) { icon = '📸🎤'; label = 'PHOTO + VOICE'; }
 else if (hasPhoto) { icon = '📸'; label = 'PHOTO'; }
 else if (hasVoice) { icon = '🎤'; label = 'VOICE CLIP'; }
 else if (hasVideo) { icon = '🎬'; label = 'VIDEO'; }

 notification += icon + ' ' + label + ' RECEIVED\n\n';
 notification += 'From: ' + phone + '\n';
 if (message) notification += 'Text: ' + message + '\n';
 notification += '\nMedia (' + numMedia + '):\n';
 media.forEach(function(m) {
 notification += ' ' + m.type + '\n ' + m.url + '\n';
 });
 notification += '\nSID: ' + messageSid;
 } else {
 notification += '💬 SMS RECEIVED\n\n';
 notification += 'From: ' + phone + '\n';
 notification += 'Text: ' + message + '\n';
 notification += '\nSID: ' + messageSid;
 }

 results.push({
 json: {
 notification: notification,
 phone: phone,
 message: message,
 numMedia: numMedia,
 messageSid: messageSid
 }
 });
}

return results;

