// Category to image prompt mapping - with safety checks
try {
  const input = $input.first().json;
  const category = input.body?.category || input.category || 'bip_milestone';
  const content = input.body?.content || input.content || '';
  const post_id = input.body?.post_id || input.post_id || 'unknown';

  // Extract key theme from content (first line or main point)
  const firstLine = (content.split('\n')[0] || '').replace(/[^a-zA-Z0-9 ]/g, '').trim() || 'Fitness achievement';

  const prompts = {
    'bip_milestone': `Create a celebratory social media graphic for a fitness business achievement. Theme: "${firstLine}". Style: Modern, bold typography on dark gradient background (purple to blue). Include subtle confetti or celebration elements. Professional, inspiring, clean design. Text should be minimal and impactful. Square format 1080x1080.`,

    'bip_tech': `Create a clean tech infographic for fitness business automation. Theme: "${firstLine}". Style: Modern dark theme with cyan/teal accents. Show abstract tech elements (code snippets, workflow diagrams, or connected nodes). Professional, sleek, developer-friendly aesthetic. Square format 1080x1080. Minimal text, focus on visual impact.`,

    'bip_behind_scenes': `Create an authentic lifestyle graphic for a fitness entrepreneur's day. Theme: "${firstLine}". Style: Warm, motivational, sunrise/sunset gradient background. Include subtle fitness or productivity icons. Professional but approachable. Square format 1080x1080. Inspirational without being cheesy.`
  };

  const prompt = prompts[category] || prompts['bip_milestone'];

  return [{
    json: {
      prompt: prompt,
      category: category,
      post_id: post_id,
      content_preview: firstLine
    }
  }];
} catch (e) {
  return [{
    json: {
      error: e.message,
      prompt: 'Create a celebratory fitness graphic',
      category: 'unknown',
      post_id: 'error'
    }
  }];
}

