    reason: 'Category does not require image'
  }
}];

// Aggregate all data into a digest
const allItems = $input.all();

// Get data from each source (items come from parallel branches)
let emails = [];
let forms = [];
let smsResponses = [];

for (const item of allItems) {
 if (item.json.threadId) {
 // Gmail data has threadId
 emails.push(item.json);
 } else if (item.json.Score !== undefined) {
 // Form data has Score
 forms.push(item.json);
 } else if (item.json.Category !== undefined) {
 // SMS data has Category
 smsResponses.push(item.json);
 }
}

// Filter to last 24 hours
const oneDayAgo = new Date(Date.now() - 24 agent-bridge agent-bridge.log api.log bridge.log dev-sandbox ec2-hardening.sh enhance-v5-with-v417.py fitness-influencer inject-v414-endpoints.py inject-v415-endpoints.py inject-v417-advanced-resilience.py inject-v5-consolidated.py inject-v5-phase2.py n8n-workflows v5-ultra-inject.py v5-ultra-optimization.py 60 agent-bridge agent-bridge.log api.log bridge.log dev-sandbox ec2-hardening.sh enhance-v5-with-v417.py fitness-influencer inject-v414-endpoints.py inject-v415-endpoints.py inject-v417-advanced-resilience.py inject-v5-consolidated.py inject-v5-phase2.py n8n-workflows v5-ultra-inject.py v5-ultra-optimization.py 60 agent-bridge agent-bridge.log api.log bridge.log dev-sandbox ec2-hardening.sh enhance-v5-with-v417.py fitness-influencer inject-v414-endpoints.py inject-v415-endpoints.py inject-v417-advanced-resilience.py inject-v5-consolidated.py inject-v5-phase2.py n8n-workflows v5-ultra-inject.py v5-ultra-optimization.py 1000);

const recentForms = forms.filter(f => {
 const ts = new Date(f.Timestamp);
 return ts > oneDayAgo;
});

const recentSMS = smsResponses.filter(s => {
 const ts = new Date(s.Timestamp);
 return ts > oneDayAgo;
});

// Count by category
const hotLeads = recentSMS.filter(s => s.Category === 'HOT_LEAD').length;
const warmLeads = recentSMS.filter(s => s.Category === 'WARM_LEAD').length;
const optOuts = recentSMS.filter(s => s.Category === 'OPT_OUT').length;

const highQualityForms = recentForms.filter(f => f.Quality === 'HIGH').length;

// Build digest
const digest = {
 date: new Date().toLocaleDateString('en-US', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' }),
 summary: {
 unreadEmails: emails.length,
 newFormSubmissions: recentForms.length,
 newSMSResponses: recentSMS.length,
 hotLeads: hotLeads,
 warmLeads: warmLeads,
 optOuts: optOuts,
 highQualityForms: highQualityForms
 },
 actionItems: [],
 details: {
 emails: emails.slice(0, 10).map(e => ({ from: e.from?.emailAddress, subject: e.subject })),
 hotLeadDetails: recentSMS.filter(s => s.Category === 'HOT_LEAD').map(s => ({ phone: s.Phone, message: s.Message })),
 highQualityFormDetails: recentForms.filter(f => f.Quality === 'HIGH').map(f => ({ name: f.Name, email: f.Email, phone: f.Phone }))
 }
};

// Generate action items
if (hotLeads > 0) {
 digest.actionItems.push(`🔥 ${hotLeads} HOT LEADS need immediate follow-up!`);
}
if (highQualityForms > 0) {
 digest.actionItems.push(`🎯 ${highQualityForms} high-quality form submissions to review`);
}
if (emails.length > 20) {
 digest.actionItems.push(`📧 ${emails.length} unread emails - consider inbox triage`);
}
if (optOuts > 0) {
 digest.actionItems.push(`⚠️ ${optOuts} opt-outs processed - verify removal from sequences`);
}

return [{ json: digest }];

