parameters.jsCode:
const items = $input.all();
for (const item of items) {
  const d = item.json.body || item.json;
  item.json = {};
  item.json.lead_id = 'form_' + Date.now();
  item.json.timestamp = new Date().toISOString();
  item.json.name = d.name || d.full_name || 'Unknown';
  item.json.email = d.email || '';
  item.json.phone = d.phone || '';
  item.json.company = d.company || 'Not provided';
  item.json.message = d.message || '';
  item.json.source = d.source || 'website';
  let score = 0;
  if (item.json.email && item.json.email.includes('@')) score += 2;
  if (item.json.phone && item.json.phone.length >= 10) score += 3;
  if (item.json.message && item.json.message.length > 10) score += 2;
  const signals = ['interested','quote','price','booking','fire','event','wedding','need'];
  const msg = (item.json.message || '').toLowerCase();
  if (signals.some(s => msg.includes(s))) score += 3;
  item.json.score = score;
  if (score >= 7) { item.json.quality = 'HIGH'; }
  else if (score >= 4) { item.json.quality = 'MEDIUM'; }
  else { item.json.quality = 'LOW'; }
}
return items;

